sql:
SELECT AVG(weight) AS Average_Weight
FROM players
WHERE league_id = (SELECT league_id FROM teams WHERE team_id = 10) AND experience > 5;

SELECT MAX(touchdowns)
FROM player_game_stats
WHERE player_id = 1;

SELECT AVG(height) AS average_height
FROM players
WHERE experience > 10;

SELECT MAX(rushing_yards)
FROM player_game_stats
WHERE player_id = 1;

SELECT MIN(birth_date) AS oldest_player_birth_date
FROM players
WHERE league_id = (SELECT league_id FROM leagues WHERE league_name = 'NFL');

external_knowledge:
- 'better at getting the ball to their teammates' implies higher average passing completions;
- 'typical performance in passing the ball and running with it' refers to the average passing completions and average rushing yards;
- 'league's usual standard' means the general average of passing completions across all players.
